/* Counter hook */
const useCounter=(target,duration=2000,active=false)=>{const [val,setVal]=useState(0);useEffect(()=>{if(!active)return;let start=null;const num=parseInt(target);const step=(ts)=>{if(!start)start=ts;const p=Math.min((ts-start)/duration,1);setVal(Math.floor(p*num));if(p<1)requestAnimationFrame(step);};requestAnimationFrame(step);},[active,target,duration]);return val;};

